  ('social-worker-moex-06870', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作實務在處理倫理兩難困境時，必須將一些規範的優先順序加以排列，以利抉擇之參考。正確的', '["最小傷害原則", "案主自決原則", "隱私保密原則", "保護案主生命"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "6dd28d6f1360", "answer_pdf_sha1": "ff4bc151c740", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06871', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會個案工作為配合社會變遷與脈動，未來努力的方向有那些？①加強本土經驗的整理  ②重視責信，', '["提升解決倫理議題的能力", "強調精神病理治療的理論與實務", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "6dd28d6f1360", "answer_pdf_sha1": "ff4bc151c740", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 29, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06872', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '以團體為實施的對象時，下列敘述何者正確？①治療團體的組成成員通常都有嚴重的情緒、行為或個人', '["任務團體是為了處理特別事務而成立的團體，組成成員愈同質性愈好", "焦點團體是為單一主 題的討論而形成的團體，通常是為了難以透過個別訪談而取得資訊及想法而成立的團體", "成長團體在 促進個人的身心發展，如少女的身心發展團體一定是混合性別的團體", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "6dd28d6f1360", "answer_pdf_sha1": "ff4bc151c740", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 30, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06873', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '團體發展可分為團體初期、權力與控制、親密、區分以及分離等 5 階段，各階段的特徵與組員行為，下', '["團體初期成員的行為常有趨避行為", "團體在第二階段的特徵是次團體鼎立，小團 體成員關係鞏固", "第三階段團體的文化、風格與價值觀開始成型", "第四階段團體將發展一個熟悉的 參考架構"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "6dd28d6f1360", "answer_pdf_sha1": "ff4bc151c740", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06874', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '請問下列何者為團體結束階段的重要工作？①協助團員覺察他所學習的內容  ②建立團體運作法則與行', '["鼓勵團員表達正負向的情緒", "評鑑團體目標的達成程度", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "6dd28d6f1360", "answer_pdf_sha1": "ff4bc151c740", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 32, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06875', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '團體工作者在團體中自我表露感受和經驗，不是出於被迫而是為了有利於目標的達成。因此團體工作者', '["團體初期宜鼓勵成員相互自我表露", "團體工作者所表露的 訊息，應與當時團體的情境有關", "團體工作者最好避免分享私人的感受和經驗", "團體工作者所表露 的訊息，應具有正面意義"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "6dd28d6f1360", "answer_pdf_sha1": "ff4bc151c740", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06876', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '在團體最初階段，領導者要評估和強化團體的凝聚力。下列何者為提升團體凝聚力的積極方法？①建立', '["避免成員間的衝突", "訂定易於達成的團體目標", "建立團體信任感", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "6dd28d6f1360", "answer_pdf_sha1": "ff4bc151c740", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 34, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06877', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '團體工作者對文化因素如何影響團體行為應是敏銳的，所以不應該有下列那項作為？', '["領導者與成員之間的背景應該契合", "領導者應該依自己的價值觀和語言模式去和成員建立關係", "領導者應在招募成員時，仔細評估成員文化背景的異同", "領導者應期待成員對贊助機構的認同"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "6dd28d6f1360", "answer_pdf_sha1": "ff4bc151c740", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06878', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', 'Wilson對美國Inner City的社區研究，試圖瞭解為什麼許多都會區會出現難以翻身的底層階級（underclass）， 發現其原因有：黑人中產階級或生活較為穩定的勞工階級搬出內城市，到生活條件較好的地方居住，區 域內的基本單位（如教會、學校、商店等）隨著沒落…等。請問此研究立基於何種理論？', '["生態系統理論", "優勢觀點", "激進觀點", "社會學習理論"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "6dd28d6f1360", "answer_pdf_sha1": "ff4bc151c740", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06879', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '依據Rothman的社區工作實務模式，下列敘述何者正確？', '["社會行動模式關注社區的社會問題、住宅及休閒等，期待解決社區的實質問題", "地方發展模式關注社區的冷漠、疏離，期待社區以民主方式解決社區問題", "社會計畫模式改變的策略是透過對質、直接行動、談判、協商的技術", "地方發展模式改變的策略是蒐集問題資料，採取最合理的行動"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "6dd28d6f1360", "answer_pdf_sha1": "ff4bc151c740", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
